// Normalize input and build 3 search queries
const input = $input.first().json;
const { run_id, module, scope, metro_id, opportunity_id, query_profile, callback_url } = input;

const orgName = query_profile?.organization || '';
const metro = query_profile?.metro || '';
const knowledge = query_profile?.knowledge || {};

const queries = [];

if (scope === 'opportunity' && orgName) {
  queries.push(`${orgName} leadership team staff directory`);
  queries.push(`${orgName} new hire executive appointment`);
  queries.push(`${orgName} board members key personnel`);
} else if (scope === 'metro' && metro) {
  queries.push(`${metro} nonprofit leadership changes`);
  queries.push(`${metro} community organization executive directors`);
  queries.push(`${metro} digital equity broadband program managers`);
}

if (queries.length === 0) {
  queries.push('nonprofit digital equity leadership staff');
}

return queries.map((q, i) => ({
  json: {
    run_id,
    module,
    scope,
    metro_id,
    opportunity_id,
    callback_url,
    query: q,
    query_index: i,
    limit: 10
  }
}));

// Merge and pre-filter results from all queries
const allItems = $input.all();
const seenUrls = new Set();
const results = [];

for (const item of allItems) {
  const data = item.json?.data || item.json?.results || [];
  if (!Array.isArray(data)) continue;

  for (const r of data) {
    const url = (r.url || r.sourceUrl || '').toLowerCase().trim();
    if (!url || seenUrls.has(url)) continue;
    seenUrls.add(url);

    results.push({
      url: r.url || r.sourceUrl || '',
      title: r.title || r.metadata?.title || '',
      snippet: r.markdown?.substring(0, 500) || r.description || '',
      source: r.metadata?.sourceURL || url
    });
  }
}

// Get context from first item
const ctx = $input.first()?.json || {};

return [{
  json: {
    run_id: ctx.run_id,
    module: ctx.module,
    scope: ctx.scope,
    metro_id: ctx.metro_id,
    opportunity_id: ctx.opportunity_id,
    callback_url: ctx.callback_url,
    results,
    result_count: results.length
  }
}];

