// Build callback payload
const ctx = $input.first().json;
const mergeData = $node['Merge & Pre-Filter'].json;
const extractRaw = $node['LLM Extract People'].json?.message?.content || '{"people":[]}';
const briefingRaw = $node['LLM Briefing'].json?.message?.content || '{}';

let extracted = { people: [] };
try { extracted = JSON.parse(extractRaw); } catch(e) { extracted = { people: [] }; }

let briefingJson = {};
try { briefingJson = JSON.parse(briefingRaw); } catch(e) { briefingJson = { highlights: [], urgent: [], new_items: [], what_changed: [], gaps_and_next_queries: [], helpful_sources: [] }; }

// Build items from extracted people
const items = (extracted.people || []).map(p => ({
  canonical_url: p.source_url || `person:${(p.name||'unknown').toLowerCase().replace(/\s+/g, '-')}`,
  source_url: p.source_url || null,
  title: p.name || 'Unknown',
  snippet: [p.title, p.organization_name].filter(Boolean).join(' at '),
  organization_name: p.organization_name || null,
  extracted: p
}));

// Build briefing_md from JSON
const lines = ['# People Discovery Briefing\n'];
if (briefingJson.highlights?.length) {
  lines.push('## Highlights');
  briefingJson.highlights.forEach(h => lines.push(`- **${h.title}**: ${h.why_it_matters}`));
  lines.push('');
}
if (briefingJson.urgent?.length) {
  lines.push('## ⚡ Urgent');
  briefingJson.urgent.forEach(u => lines.push(`- **${u.title}**: ${u.why_this_week}`));
  lines.push('');
}
if (briefingJson.new_items?.length) {
  lines.push('## New');
  briefingJson.new_items.forEach(n => lines.push(`- **${n.title}**: ${n.one_liner}`));
  lines.push('');
}
const briefingMd = lines.join('\n');

return [{
  json: {
    run_id: mergeData.run_id,
    status: 'completed',
    module: mergeData.module || 'people',
    scope: mergeData.scope,
    metro_id: mergeData.metro_id || null,
    opportunity_id: mergeData.opportunity_id || null,
    items,
    briefing_json: briefingJson,
    briefing_md: briefingMd,
    stats: {
      search_results: mergeData.result_count || 0,
      people_extracted: items.length
    }
  }
}];
